package ru.memearena.scout.application; import org.springframework.dao.DataIntegrityViolationException; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.meme.domain.Meme; import ru.memearena.scout.domain.*; import ru.memearena.scout.infrastructure.*; import java.time.*; import java.util.*;
@Service public class ScoutService{ private final UserScoutStatsRepository stats; private final MemePredictionRepository preds; private final ScoutPolicies policies; private final AchievementService achievements; public ScoutService(UserScoutStatsRepository stats,MemePredictionRepository preds,ScoutPolicies policies,AchievementService achievements){this.stats=stats;this.preds=preds;this.policies=policies;this.achievements=achievements;} public UserScoutStats ensureStats(UUID u,Instant now){return stats.findById(u).orElseGet(()->stats.save(new UserScoutStats(u,now)));} @Transactional public void createStats(UUID u,Instant now){ensureStats(u,now);} public Optional<MemePrediction> maybeCreatePrediction(UUID user,Meme meme,UUID voteId,long battlesBefore,int ratingBefore,Instant now){boolean exists=preds.existsByUserIdAndMemeId(user,meme.getId()); if(!policies.eligible(meme,user,exists,now))return Optional.empty(); try{var p=preds.saveAndFlush(new MemePrediction(UUID.randomUUID(),user,meme.getId(),voteId,battlesBefore,ratingBefore,now)); var s=ensureStats(user,now); s.predictionCreated(now); stats.save(s); achievements.unlock(user,"FIRST_PREDICTION",now); return Optional.of(p);}catch(DataIntegrityViolationException e){return Optional.empty();}} public UserScoutStats stats(UUID u,Instant now){return ensureStats(u,now);} }
